from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """
    Convert a list of Triples about food into a single fluent sentence.
    """
    if not triples:
        return ""

    # Helper to turn a single triple into a phrase
    def triple_to_phrase(t: Triple) -> str:
        s, p, o = t.subject, t.predicate, t.object
        # Expanded natural language mappings for all supported predicates
        if p == "country":
            return f"{s} is from {o}"
        if p == "ingredient":
            return f"{s} contains {o}"
        if p == "region":
            return f"{s} originates from {o}"
        if p == "division":
            return f"{s} belongs to the division {o}"
        if p == "family":
            return f"{s} is in the family {o}"
        if p == "order":
            return f"{s} is classified under the order {o}"
        if p == "class":
            return f"{s} belongs to the class {o}"
        if p == "genus":
            return f"{s} belongs to the genus {o}"
        if p == "course":
            return f"{s} is served as a {o}"
        if p == "capital":
            return f"The capital of {s} is {o}"
        if p == "leader":
            return f"The leader of {s} is {o}"
        if p == "leaderTitle":
            return f"The title of the leader of {s} is {o}"
        if p == "alternativeName":
            return f"{s} is also known as {o}"
        if p == "creator":
            return f"{s} was created by {o}"
        if p == "creatorOfDish":
            return f"{s} was created by {o}"
        if p == "mainIngredient":
            return f"The main ingredients of {s} are {o}"
        if p == "dishVariation":
            return f"{s} can vary with {o}"
        if p == "servingTemperature" or p == "served":
            return f"{s} is served {o}"
        if p == "year":
            return f"{s} was introduced in {o}"
        if p == "carbohydrate":
            return f"{s} contains {o} of carbohydrates"
        if p == "fat":
            return f"{s} contains {o} of fat"
        if p == "protein":
            return f"{s} contains {o} of protein"
        if p == "servingSize":
            return f"The serving size of {s} is {o}"
        if p == "related":
            return f"{s} is related to {o}"
        if p == "similarDish":
            return f"{s} is similar to {o}"
        if p == "isPartOf":
            return f"{s} is part of {o}"
        if p == "currency":
            return f"The currency of {s} is {o}"
        if p == "demonym":
            return f"The demonym for {s} is {o}"
        if p == "language":
            return f"The language spoken in {s} is {o}"
        if p == "officialLanguage":
            return f"The official language of {s} is {o}"
        if p == "ethnicGroup":
            return f"The ethnic group of {s} is {o}"
        if p == "foundationPlace":
            return f"{s} was founded in {o}"
        # Default generic phrasing for any unspecified predicate
        return f"{s} {p} {o}"

    # Build more fluent sentence by grouping predicates per subject
    from collections import defaultdict

    subject_map = defaultdict(list)
    for t in triples:
        subject_map[t.subject].append(t)

    # Order subjects so that the one with most information comes first
    ordered_subjects = sorted(subject_map.items(), key=lambda kv: len(kv[1]), reverse=True)

    # Build the main clause from the primary subject
    primary_subj, primary_triples = ordered_subjects[0]
    primary_parts = []
    for t in primary_triples:
        phrase = triple_to_phrase(t)
        if phrase.lower().startswith(primary_subj.lower() + " "):
            phrase = phrase[len(primary_subj) + 1:]
        primary_parts.append(phrase.rstrip('.'))
    if len(primary_parts) == 1:
        sentence = f"{primary_subj} {primary_parts[0]}"
    else:
        sentence = f"{primary_subj} " + ", ".join(primary_parts[:-1]) + ", and " + primary_parts[-1]

    # Append additional subjects as relative clauses for fluency
    for subj, tlist in ordered_subjects[1:]:
        rel_parts = []
        for t in tlist:
            phrase = triple_to_phrase(t)
            if phrase.lower().startswith(subj.lower() + " "):
                phrase = phrase[len(subj) + 1:]
            rel_parts.append(phrase.rstrip('.'))
        if rel_parts:
            if len(rel_parts) == 1:
                rel_clause = rel_parts[0]
            else:
                rel_clause = ", ".join(rel_parts[:-1]) + ", and " + rel_parts[-1]
            sentence += f", which {rel_clause}"
    # Ensure final punctuation
    if not sentence.endswith('.'):
        sentence += '.'
    return sentence

# EVOLVE-BLOCK-END

